head.script:
/**
 * 화면 초기화에 필요한 로직을 수행한다.
 * @param
 * @return
 */
scwin.initScreen = function() {
	// 화면초기화 공통 함수 호출
	comLib.initForm($p, "ECSCL1100000", {"initScreenCallback" : scwin.searchDatas});
};

/**
 * 화면 초기 데이터들을 조회한다.
 * @param
 * @return
 */
scwin.searchDatas = function() {
	// 조회조건 설정
	scwin.initSearchParam();
	// 화면 데이터 조회
	scwin.btnInqire_onclick();
};

/**
 * 조회조건 초기화에 필요한 로직을 수행한다.
 * @param
 * @return
 */
scwin.initSearchParam = function() {
	var basinCd = "ALL";
	var setcscDivCd = "ALL";
	var endDtD = utilLib.getCurrentDate("yyyyMMdd");
	//var strtDtD = utilLib.addDay(endDtD, -7);
	var strtDtD = endDtD;
	var endDtM = utilLib.getCurrentDate("yyyyMM");
	//var strtDtM = utilLib.addMonth(endDtM, -1);
	var strtDtM = endDtM;
	var endDtY = utilLib.getCurrentDate("yyyy");
	//var strtDtY = String(Number(endDtY) - 1);
	var strtDtY = endDtY;

	var params = $p.getParameter("param");
	if (params) {
		if (params.type) {
			radYmdBy.setValue(params.type);
		}
		if (params.year) {
			if (radYmdBy.getValue() == "Y") {
				endDtY = String(params.year);
				strtDtY = String(params.year);
			} else if (radYmdBy.getValue() == "M") {
				if (params.month) {
					strtDtM = String(params.year) + String(params.month);
				} else {
					if (strtDtM.substr(0, 4) == params.year) {
						endDtM = String(params.year) + strtDtM.substr(4, 2);
						strtDtM = String(params.year) + "01";
					} else {
						endDtM = String(params.year) + "12";
						strtDtM = String(params.year) + "01";
					}
				}
			} else {
			}
		}
		if (params.setcscDivCd) {
			setcscDivCd = params.setcscDivCd;
			acbSetcsc.setValue(setcscDivCd);
		}
	}

	dmaSearchParam.set("strtDtD", strtDtD);
	dmaSearchParam.set("endDtD", endDtD);
	dmaSearchParam.set("strtDtM", strtDtM);
	dmaSearchParam.set("endDtM", endDtM);
	dmaSearchParam.set("strtDtY", strtDtY);
	dmaSearchParam.set("endDtY", endDtY);
	dmaSearchParam.set("basinCd", basinCd);
	dmaSearchParam.set("setcscCd", setcscDivCd);
	dmaSearchParam.set("elcpwstnCd", "ALL");
};

/**
 * 조회조건에 맞게 data를 조회한다.
 * @param
 * @return
 */
scwin.btnInqire_onclick = function() {
	var ecsBasinDivCd = dmaSearchParam.get("basinCd");
	var ecsSetcscDivCd = dmaSearchParam.get("setcscCd");
	var ecsElcpwstnDivCd = dmaSearchParam.get("elcpwstnCd");
	var ymdBy = radYmdBy.getValue();
	var cnd = "daly";

	if (ymdBy == "D") {
		var strtDate = dmaSearchParam.get("strtDtD");
		var endDate = dmaSearchParam.get("endDtD");

		if (String(strtDate).length != 8 || String(endDate).length != 8) {
			// 조회기간이 올바르지 않습니다.
			alert(utilLib.getMessage("ECS.INFO.00011")[0]);
			return;
		} else if (utilLib.minusDates(strtDate, endDate) > 31 ? true : false) {
			// 조회기간은 {0}을 넘어갈 수 없습니다. 다시 설정해 주세요.
			alert(utilLib.getMessage("ECS.INFO.00012", "31일")[0]);
			return;
		} else if (parseInt(strtDate) > parseInt(endDate)) {
			// 시작년월일이 종료년월일보다 클수 없습니다.
			alert(utilLib.getMessage("ECS.INFO.00013")[0]);
			return;
		}
	} else if (ymdBy == "M") {
		var strtDate = dmaSearchParam.get("strtDtM");
		var endDate = dmaSearchParam.get("endDtM");
		cnd = "mnby";

		if (String(strtDate).length != 6 || String(endDate).length != 6) {
			// 조회기간이 올바르지 않습니다.
			alert(utilLib.getMessage("ECS.INFO.00011")[0]);
			return;
		} else if (utilLib.minusMonths(strtDate, endDate) > 12 ? true : false) {
			// 조회기간은 {0}을 넘어갈 수 없습니다. 다시 설정해 주세요.
			alert(utilLib.getMessage("ECS.INFO.00012", "12개월")[0]);
			return;
		} else if (parseInt(strtDate) > parseInt(endDate)) {
			// 시작년월이 종료년월일보다 클수 없습니다.
			alert(utilLib.getMessage("ECS.INFO.00014")[0]);
			return;
		}
	} else if (ymdBy == "Y") {
		var strtDate = dmaSearchParam.get("strtDtY");
		var endDate = dmaSearchParam.get("endDtY");
		cnd = "yyby";

		if (String(strtDate).length != 4 || String(endDate).length != 4) {
			// 조회기간이 올바르지 않습니다.
			alert(utilLib.getMessage("ECS.INFO.00011")[0]);
			return;
		} else if (utilLib.minusYears(strtDate, endDate) > 5 ? true : false) {
			// 조회기간은 {0}을 넘어갈 수 없습니다. 다시 설정해 주세요.
			alert(utilLib.getMessage("ECS.INFO.00012", "5년")[0]);
			return;
		} else if (parseInt(strtDate) > parseInt(endDate)) {
			// 시작년이 종료년보다 클수 없습니다.
			alert(utilLib.getMessage("ECS.INFO.00015")[0]);
			return;
		}
	} else {
		return;
	}

	// 라디오버튼 선택에 따라 그리드 타이틀을 변경한다_240104
	var radymdByNm = radYmdBy.getText();
	spnSubTitle.setLabel("발전원 정산" + "(" + radymdByNm + ")");

	var queryString = `?strtDt=${strtDate}`;
	queryString += `&endDt=${endDate}`;
	queryString += `&cnd=${cnd}`;
	queryString += `&ecsBasinDivCd=${ecsBasinDivCd}`;
	queryString += `&ecsSetcscDivCd=${ecsSetcscDivCd}`;
	queryString += `&ecsElcpwstnDivCd=${ecsElcpwstnDivCd}`;

	var option = {
		action : "cl/setcscexcclc/retrieve-setcsc-excclc.do"
			+ queryString,
		method : "get",
		resData : dltSetcscExcclcList,
		success : "scwin.inqireCallback",
		isShowMeg : false
	};
	ajaxLib.executeAjax($p, option);
};

/**
 * 조회 CallBack 실행한다.
 * @param
 * @return
 */
scwin.inqireCallback = function() {
	spnTotalRow.setValue(dltSetcscExcclcList.getRowCount());
	var ymdBy = radYmdBy.getValue();

	if (ymdBy == "D") {
		grdSetcscExcclc.setDisplayFormat("ymd", "####-##-##");
		grdSetcscExcclc.setHeaderValue("hYmd", "일자");
	} else if (ymdBy == "M") {
		grdSetcscExcclc.setDisplayFormat("ymd", "####-##");
		grdSetcscExcclc.setHeaderValue("hYmd", "년월");
	} else if (ymdBy == "Y") {
		grdSetcscExcclc.setDisplayFormat("ymd", "####");
		grdSetcscExcclc.setHeaderValue("hYmd", "년도");
	}

	scwin.inqireEpwrDelngFee();
};

scwin.inqireEpwrDelngFee = function() {
	var ecsBasinDivCd = dmaSearchParam.get("basinCd");
	var ecsSetcscDivCd = dmaSearchParam.get("setcscCd");
	var ecsElcpwstnDivCd = dmaSearchParam.get("elcpwstnCd");
	var ymdBy = radYmdBy.getValue();
	var cnd = "daly";

	if (ymdBy == "D") {
		var strtDate = dmaSearchParam.get("strtDtD");
		var endDate = dmaSearchParam.get("endDtD");
	} else if (ymdBy == "M") {
		var strtDate = dmaSearchParam.get("strtDtM");
		var endDate = dmaSearchParam.get("endDtM");
		cnd = "mnby";
	} else if (ymdBy == "Y") {
		var strtDate = dmaSearchParam.get("strtDtY");
		var endDate = dmaSearchParam.get("endDtY");
		cnd = "yyby";
	} else {
		return;
	}

	var queryString = `?strtDt=${strtDate}`;
	queryString += `&endDt=${endDate}`;
	queryString += `&cnd=${cnd}`;
	queryString += `&ecsBasinDivCd=${ecsBasinDivCd}`;
	queryString += `&ecsSetcscDivCd=${ecsSetcscDivCd}`;
	queryString += `&ecsElcpwstnDivCd=${ecsElcpwstnDivCd}`;

	var option = {
		action : "cl/setcscexcclc/retrieve-epwr-delng-fee.do"
			+ queryString,
		method : "get",
		resData : dltEpwrDelngFee,
		success : "scwin.inqireEpwrDelngFeeCallback",
		isShowMeg : false
	};
	ajaxLib.executeAjax($p, option);
};

scwin.inqireEpwrDelngFeeCallback = function() {
	var epwrDelngFeeDatas = dltEpwrDelngFee.getAllJSON();
	var sum = epwrDelngFeeDatas.reduce((sum, obj) => sum += Number(obj.epwrDelngFee), 0);
	sum += "원";
	grdSetcscExcclc.setFooterData("fEpwrDelngFee", sum);
};

/**
 * 라디오버튼 선택에 따라 조회연도를 변경한다.
 * @param
 * @return
 */
scwin.radYmdBy_onchange = function() {
	var ymdBy = radYmdBy.getValue();

	if (ymdBy == "D") {
		grpCalDNm.setStyle("display", "");
		grpCalDBox.setStyle("display", "");
		grpCalDNm.setStyle("display", "none");
		grpCalMBox.setStyle("display", "none");
		grpCalYNm.setStyle("display", "none");
		grpCalYBox.setStyle("display", "none");
	} else if (ymdBy == "M") {
		grpCalDNm.setStyle("display", "none");
		grpCalDBox.setStyle("display", "none");
		grpCalDNm.setStyle("display", "");
		grpCalMBox.setStyle("display", "");
		grpCalYNm.setStyle("display", "none");
		grpCalYBox.setStyle("display", "none");
	} else if (ymdBy == "Y") {
		grpCalDNm.setStyle("display", "none");
		grpCalDBox.setStyle("display", "none");
		grpCalDNm.setStyle("display", "none");
		grpCalMBox.setStyle("display", "none");
		grpCalYNm.setStyle("display", "");
		grpCalYBox.setStyle("display", "");
	} else {
		return;
	}
};

/**
 * 조회박스 선택별 값을 세팅한다.
 * @param info
 * @return
 */
scwin.acbBasin_onviewchange = function(info) {
	var ecsBasinDivCd = info.newValue;
	dmaSearchParam.set("basinCd", ecsBasinDivCd);
	var ecsSetcscDivCd = dmaSearchParam.get("setcscCd");

	var queryString = `&ecsBasinDivCd=${ecsBasinDivCd}`;
	queryString += `&ecsSetcscDivCd=${ecsSetcscDivCd}`;
	var option = {
		action : "zz/cmmn/retrieve-prdctn-cnd.do?cnd=elcpwstn"
			+ queryString,
		method : "get",
		resData : dltAutoCondition3,
		success : "",
		isShowMeg : false
	};
	ajaxLib.executeAjax($p, option);
	dmaSearchParam.set("elcpwstnCd", "ALL");
};

scwin.acbSetcsc_onviewchange = function(info) {
	var ecsSetcscDivCd = info.newValue;
	dmaSearchParam.set("setcscCd", ecsSetcscDivCd);
	var ecsBasinDivCd = dmaSearchParam.get("basinCd");

	var queryString = `&ecsBasinDivCd=${ecsBasinDivCd}`;
	queryString += `&ecsSetcscDivCd=${ecsSetcscDivCd}`;
	var option = {
		action : "zz/cmmn/retrieve-prdctn-cnd.do?cnd=elcpwstn"
			+ queryString,
		method : "get",
		resData : dltAutoCondition3,
		success : "",
		isShowMeg : false
	};
	ajaxLib.executeAjax($p, option);
	dmaSearchParam.set("elcpwstnCd", "ALL");
};

scwin.acbElcpwstn_onviewchange = function(info) {
	dmaSearchParam.set("elcpwstnCd", info.newValue);
};

//============================================================================================
// 엑셀
//============================================================================================
/**
 * 그리드의 내용을 엑셀로 다운로드 한다.
 * @return
 */
scwin.btnDownExcel_onclick = function() {
	var menuNm = $p.getComponentById("wfm_title").scope.$p.getComponentById("tbxScreenTitle").getValue();
	var subTitleNm = spnSubTitle.getValue();
	// 엑셀 내부 타이틀 추가_240105
	var infoArr = [];
	var infoObj = {
		rowIndex 	: 0,
		colIndex 	: 0,
		rowSpan 	: 0,
		colSpan 	: 11,
		text 		: `${menuNm}_` + `${subTitleNm}`,
		textAlign 	: "left"
	};
	infoArr.push(infoObj);

	comLib.downloadExcel(grdSetcscExcclc, {
		fileName : `${menuNm}_` + `${subTitleNm}.xlsx`,
		type : 1,
		autoSizeColumn : true,
		useDataFormat: true,
		applyDataFormat : true
	}, infoArr);
};
